+// looksLikeAgentName checks if a string looks like an AdjectiveNoun agent name.
+func looksLikeAgentName(s string) bool {
+	if strings.Contains(s, " ") || strings.Contains(s, "_") || strings.Contains(s, "-") {
+		return false
+	}
+	if len(s) == 0 || s[0] < 'A' || s[0] > 'Z' {
+		return false
+	}
+	for i := 1; i < len(s); i++ {
+		if s[i] >= 'A' && s[i] <= 'Z' {
+			return true
+		}
+	}
+	return false
 }

